$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$sandbox=Join-Path ([IO.Path]::GetTempPath()) ('ueef-learning-'+[guid]::NewGuid().ToString('N'));try{New-Item -ItemType Directory -Path $sandbox|Out-Null;$r=(& (Join-Path $root 'scripts\record-learning-loop.ps1') -Failure 'Regression test failed' -Lesson 'Add regression coverage before retry.' -Root $sandbox -Json|Out-String)|ConvertFrom-Json;if(!$r.requiresHumanApproval -or $r.automaticRuleChange -or $r.record.kind -ne 'lesson'){throw 'Learning loop safety contract failed.'};Write-Host 'Learning loop tests passed'}finally{if(Test-Path $sandbox){Remove-Item $sandbox -Recurse -Force}}
